    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //
        //            {
        //                "event_time": "1764779531332118705",
        //                "instrument": "ETH_USDT_Perp",
        //                "size": "23.73",
        //                "price": "3089.88",
        //                "is_rpi": false,
        //                "mark_price": "3089.360002315",
        //                "index_price": "3090.443723246",
        //                "interest_rate": "0.0",
        //                "forward_price": "0.0",
        //                "trade_id": "64796657-1",
        //                "venue": "ORDERBOOK",
        //                "is_taker_buyer": false
        //            }
        //
        // fetchMyTrades
        //
        //            {
        //                "event_time": "1764945709702747558",
        //                "instrument": "BTC_USDT_Perp",
        //                "size": "0.001",
        //                "price": "90000.0",
        //                "is_rpi": false
        //                "mark_price": "90050.164063298",
        //                "index_price": "90089.803654938",
        //                "interest_rate": "0.0",
        //                "forward_price": "0.0",
        //                "trade_id": "65424692-2",
        //                "venue": "ORDERBOOK",
        //                "is_buyer": true,
        //                "is_taker": false,
        //                "broker": "UNSPECIFIED",
        //                "realized_pnl": "0.0",
        //                "fee": "-0.00009",
        //                "fee_rate": "0.0",
        //                "order_id": "0x01010105034cddc7000000006621285c",
        //                "client_order_id": "1375879248",
        //                "signer": "0x42c9f56f2c9da534f64b8806d64813b29c62a01d",
        //                "sub_account_id": "2147050003876484",
        //            }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "instrument");
        market = this.safeMarket(marketId, market);
        Object timestamp = this.safeIntegerProduct(trade, "event_time", 0.000001);
        Object takerOrMaker = null;
        Object isTakerBuyer = this.safeBool(trade, "is_taker_buyer");
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(isTakerBuyer, null)))
        {
            side = ((Helpers.isTrue(isTakerBuyer))) ? "buy" : "sell";
            takerOrMaker = "taker";
        } else
        {
            takerOrMaker = ((Helpers.isTrue(this.safeBool(trade, "is_taker")))) ? "taker" : "maker";
            side = ((Helpers.isTrue(this.safeBool(trade, "is_buyer")))) ? "buy" : "sell";
        }
        Object fee = null;
        Object feeString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeString, null)))
        {
            final Object finalFeeString = feeString;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", GrvtCore.this.parseNumber(finalFeeString) );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
                put( "rate", GrvtCore.this.safeNumber(trade, "fee_rate") );
            }};
        }
        final Object finalMarket_2 = market;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", GrvtCore.this.safeString(trade, "trade_id") );
            put( "timestamp", timestamp );
            put( "datetime", GrvtCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket_2, "symbol") );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", GrvtCore.this.safeString(trade, "price") );
            put( "amount", GrvtCore.this.safeString(trade, "size") );
            put( "cost", null );
            put( "fee", finalFee );
            put( "order", GrvtCore.this.safeString(trade, "order_id") );
        }}, market);
    }

    /**
     * @method
     * @name grvt#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://api-docs.grvt.io/market_data_api/#candlestick_1
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest item to fetch
     * @param {int} [limit] the maximum amount of items to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms for the ending date filter, default is the current time
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object maxLimit = 1000;
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate", false);
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, maxLimit)).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instrument", Helpers.GetValue(market, "id") );
                put( "interval", GrvtCore.this.safeString(GrvtCore.this.timeframes, timeframe, timeframe) );
            }};
            Object priceTypeMap = new java.util.HashMap<String, Object>() {{
                put( "last", "TRADE" );
                put( "mark", "MARK" );
                put( "index", "INDEX" );
            }};
            Object selectedPriceType = this.safeString(parameters, "priceType", "last");
            Helpers.addElementToObject(request, "type", this.safeString(priceTypeMap, selectedPriceType));
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", Helpers.mathMin(limit, 1000));
            }
            var requestparametersVariable = this.handleUntilOptionString("end_time", request, parameters, 1000000);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start_time", this.numberToString(Helpers.multiply(since, 1000000)));
            }
            Object response = (this.publicMarketPostFullV1Kline(this.extend(request, parameters))).join();
            //
            //    {
            //        "result": [
            //            {
            //                "open_time": "1767288240000000000",
            //                "close_time": "1767288300000000000",
            //                "open": "88178.8",
            //                "close": "88176.7",
            //                "high": "88192.7",
            //                "low": "88176.6",
            //                "volume_b": "15.32",
            //                "volume_q": "1350962.4782",
            //                "trades": 38,
            //                "instrument": "BTC_USDT_Perp"
            //            },
            //        ],
            //        "next": "eyJvcGVuVGltZSI6MTc2NzI1ODMwMDAwMDAwMDAwMH0"
            //    }
            //
            Object candles = this.safeList(response, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(candles, market, timeframe, since, limit);
        });

    }

